    uc_pub_to_first_cpc[pub] = sorted(set(first_codes))

uc_pubs = sorted(uc_pub_to_first_cpc.keys())
print('__RESULT__:')
print(json.dumps({'uc_publications': uc_pubs, 'count': len(uc_pubs)}))"}

